const src = $json;

// Luon dam bao chatInput la chuoi
let chatInput = String(src.chatInput ?? "").trim();

// Thu parse neu chatInput la JSON string
let parsed = null;
try {
  if (chatInput.startsWith("{") && chatInput.endsWith("}")) {
    parsed = JSON.parse(chatInput);
  }
} catch (_) {
  parsed = null;
}

// Lay image tu root, neu khong co thi lay tu parsed
const imageObj = src.image ?? parsed?.image ?? null;
const rawData = String(imageObj?.data ?? "").trim();
const base64 = rawData.replace(/^data:[^;]+;base64,/, "");

// Neu parsed co question rieng thi uu tien
if (parsed?.question) {
  chatInput = String(parsed.question).trim();
}

const hasImage = base64.length > 0;

return [
  {
    json: {
      action: src.action ?? "",
      sessionId: src.sessionId ?? src.sessionid ?? "",
      chatInput,
      hasImage,
      image: hasImage
        ? {
            name: imageObj?.name ?? "upload.jpg",
            mimeType: imageObj?.mimeType ?? "image/jpeg",
            data: base64,
          }
        : null,
    },
  },
];

const item = $input.first();
const data = item?.json || {};

// Nguon OCR (output tu OCR tool)
const vf = data;

// ChatInput nen duoc giu lai tu cac node truoc trong cung item
const originalChat = data.chatInput || "";

// 1) Text OCR
const baseText =
  (typeof vf.ocr_text === "string" && vf.ocr_text.trim()) ||
  (typeof vf.raw_text === "string" && vf.raw_text.trim()) ||
  (typeof vf.text === "string" && vf.text.trim()) ||
  "";

// 2) Line items
let itemsText = "";
if (Array.isArray(vf.line_items) && vf.line_items.length) {
  itemsText = vf.line_items
    .map((it, idx) => {
      const desc = it.description || it.text || "Muc khong ro";
      const qty = it.quantity ?? "";
      const amount = it.total ?? it.price ?? "";
      return `${idx + 1}. ${desc} | SL: ${qty} | Tien: ${amount}`;
    })
    .join("\n");
}

const ocrText = [baseText, itemsText].filter(Boolean).join("\n").trim();
const ocrStatus = ocrText ? "ok" : "empty";

const vendor = (vf.vendor && (vf.vendor.name || vf.vendor)) || vf.vendor_name || "";
const date = vf.date || vf.invoice_date || "";
const total = vf.total ?? vf.grand_total ?? "";

const agentInput = [
  `Cau hoi nguoi dung: ${originalChat}`,
  `Da gui anh: Co`,
  `OCR status: ${ocrStatus}`,
  `Vendor: ${vendor}`,
  `Date: ${date}`,
  `Total: ${total}`,
  "",
  "Noi dung OCR:",
  ocrText || "Khong trich xuat duoc noi dung ro rang."
].join("\n");

return [
  {
    json: {
      ...data,
      hasImage: true,
      ocrStatus,
      ocrText,
      vendor,
      date,
      total,
      chatInput: agentInput,
    },
  },
];
